// 算出上週一 ~ 上週五 5 個交易日，跳國定假日。
// 今天通常是週一 trigger，上週一 = today - 7 天。
// 假日 list 從 Config node 拿（避免硬編碼）。

const config = $('Config').first().json;
const skipList = String(config.holidaySkipList || '').split(',').map(s => s.trim()).filter(Boolean);

const now = $now;
const lastMonday = now.minus({ days: 7 });

const items = [];
for (let i = 0; i < 5; i++) {
  const d = lastMonday.plus({ days: i });
  const yyyymmdd = d.toFormat('yyyyLLdd');
  if (!skipList.includes(yyyymmdd)) {
    items.push({ json: { tradingDate: yyyymmdd } });
  }
}

if (items.length === 0) {
  // 整週皆假日（極罕見，例：春節週）→ 推送空週說明
  return [{ json: { tradingDate: null, emptyWeek: true } }];
}

return items;

// 聚合上週 5 天 (或 < 5 天) T86 資料 → 外資 net buy/sell 切片
// 外資定義：「外陸資（不含外資自營商）」(T86 idx 4)
//   idx 2 = 外陸資買進股數(不含外資自營商)
//   idx 3 = 外陸資賣出股數(不含外資自營商)
//   idx 4 = 外陸資買賣超股數(不含外資自營商)  ← 即 net，本工具使用欄位
// T86 數字單位：股 (1 張 = 1000 股)，所以 股 / 1000 = 張
// 顯示用「千張」單位 → 股 / 1000 / 1000 = 千張，與一般散戶熟悉的單位對齊

const config = $('Config').first().json;
const topN = Number(config.topN) || 5;
const threshold = Number(config.consecutiveThreshold) || 3;

const days = $input.all();

// 空週 fallback (Calc 標 emptyWeek)
if (days.length === 1 && days[0].json.emptyWeek === true) {
  return [{
    json: {
      emptyWeek: true,
      dataRange: '上週',
      dayCount: 0,
      topBuy: [], topSell: [], consecutiveBuy: [], consecutiveSell: []
    }
  }];
}

const acc = {};
const validDays = [];

days.forEach((day, dayIdx) => {
  const resp = day.json;
  if (!resp || resp.stat !== 'OK' || !Array.isArray(resp.data)) {
    // 該天無資料（颱風 / 補登失敗 / 假日漏標）→ skip 該天
    return;
  }
  validDays.push({ idx: dayIdx, title: resp.title });

  resp.data.forEach(row => {
    const code = String(row[0] || '').trim();
    const name = String(row[1] || '').trim();
    if (!code) return;

    // idx 4 = 外陸資買賣超股數(不含外資自營商) · 含千分位 comma 需 strip
    const foreignNet = parseInt(String(row[4] || '0').replace(/,/g, ''), 10) || 0;

    if (!acc[code]) acc[code] = { code, name, daily: {}, weekly: 0 };
    acc[code].daily[dayIdx] = foreignNet;
    acc[code].weekly += foreignNet;
  });
});

const all = Object.values(acc);

// 4 切片
const topBuy = [...all]
  .filter(s => s.weekly > 0)
  .sort((a, b) => b.weekly - a.weekly)
  .slice(0, topN);

const topSell = [...all]
  .filter(s => s.weekly < 0)
  .sort((a, b) => a.weekly - b.weekly)
  .slice(0, topN);

// 連續 ≥ threshold 日 → 必須在所有 valid day 都同方向 (不能跳天)
// 邏輯：擷取每檔在 valid day idx 上的 daily 值，全 > 0 = 連買
// 再依週淨額絕對值排序、截 topN，避免訊息過長 / 噪音淹沒重點
const consecutiveBuy = all.filter(s => {
  if (validDays.length < threshold) return false;
  return validDays.every(d => (s.daily[d.idx] || 0) > 0);
}).sort((a, b) => b.weekly - a.weekly).slice(0, topN);

const consecutiveSell = all.filter(s => {
  if (validDays.length < threshold) return false;
  return validDays.every(d => (s.daily[d.idx] || 0) < 0);
}).sort((a, b) => a.weekly - b.weekly).slice(0, topN);

// data range 從第一天 / 最後一天 title 抽
const parseTitle = (t) => {
  if (!t) return null;
  const m = String(t).match(/(\d+)年(\d+)月(\d+)日/);
  if (!m) return null;
  return `${m[1]}/${m[2].padStart(2, '0')}/${m[3].padStart(2, '0')}`;
};
const firstDate = parseTitle(validDays[0]?.title);
const lastDate = parseTitle(validDays[validDays.length - 1]?.title);
const dataRange = (firstDate && lastDate)
  ? `${firstDate} ~ ${lastDate}`
  : '上週';

return [{
  json: {
    emptyWeek: false,
    dataRange,
    dayCount: validDays.length,
    threshold,
    topBuy, topSell, consecutiveBuy, consecutiveSell
  }
}];

// 4 切片 → Telegram 純文字
// 不用 parse_mode（避免台股名稱含括號的 escape 問題）
// disclaimer 強制 append（不可移除）

const data = $input.first().json;

// 空週訊息
if (data.emptyWeek === true) {
  const text = [
    '📅 上週外資進出週報',
    '',
    '上週無交易日資料（連假休市）',
    '',
    '📍 資料來源: 證交所 T86 三大法人買賣超日報',
    '',
    '※ 本資訊僅供參考,不構成投資建議,投資請自行評估風險'
  ].join('\n');
  return [{ json: { messageText: text } }];
}

// 股 → 千張 (1 張 = 1000 股，整週累積 / 1000 / 1000 = 千張)
const toThousandLots = (shares) => Math.round(shares / 1000 / 1000);

const fmtBuy = (items) => items.length > 0
  ? items.map((it, i) => {
      const k = toThousandLots(it.weekly);
      return `${i + 1}. ${it.name} (${it.code})   +${k.toLocaleString()} 千張`;
    }).join('\n')
  : '(本週無)';

const fmtSell = (items) => items.length > 0
  ? items.map((it, i) => {
      const k = toThousandLots(it.weekly);
      return `${i + 1}. ${it.name} (${it.code})   ${k.toLocaleString()} 千張`;
    }).join('\n')
  : '(本週無)';

const fmtConsec = (items) => items.length > 0
  ? items.map(it => {
      const days = Object.keys(it.daily).length;
      return `- ${it.name} (${it.code})   ${days} 日連續`;
    }).join('\n')
  : '(本週無)';

const topBuyCount = data.topBuy.length;
const topSellCount = data.topSell.length;
const threshold = data.threshold || 3;

const text = [
  `📅 ${data.dataRange} 外資進出週報`,
  '',
  `🔼 外資淨買超 Top ${topBuyCount}（上週累計）`,
  fmtBuy(data.topBuy),
  '',
  `🔽 外資淨賣超 Top ${topSellCount}（上週累計）`,
  fmtSell(data.topSell),
  '',
  `🟢 連續買超 ≥ ${threshold} 日`,
  fmtConsec(data.consecutiveBuy),
  '',
  `🔴 連續賣超 ≥ ${threshold} 日`,
  fmtConsec(data.consecutiveSell),
  '',
  `📊 資料區間: ${data.dataRange} · ${data.dayCount} 個交易日`,
  '📍 資料來源: 證交所 T86 三大法人買賣超日報',
  '※「外資」= 外陸資（境外法人 + 陸資）· 不含外資自營商部位',
  '',
  '※ 本資訊僅供參考,不構成投資建議,投資請自行評估風險'
].join('\n');

return [{ json: { messageText: text } }];
